  ('fire-eq-eng-moex-00205', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法，有關室內儲 槽場所之位置、構造及設備應符合規定之敘述，下列何者錯誤？', '["儲槽專用室之儲槽側板外壁與室內牆面之距離應在50公分以上", "儲槽容量不得超過管制量之40倍，且儲存第四類公共危險物品時，除第四石油類及動植物 油類外，不得超過2萬公升", "儲槽構造：儲槽材質應為厚度3.2毫米以上之鋼板或具有同等以上性能者", "正負壓力超過500毫米水柱壓力之儲槽應設置通氣管；非壓力儲槽應設置安全裝置"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00206', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法規定，有關室 外儲槽場所儲槽儲存第四類公共危險物品，其防液堤應符合規定之敘述，下列何者錯誤？', '["單座儲槽周圍所設置防液堤之容量，應為該儲槽容量百分之一百十以上", "防液堤之高度應在50公分以上。但儲槽容量合計超過20萬公秉者，高度應在1公尺以上", "防液堤內面積不得超過6萬平方公尺", "防液堤內部設置儲槽，不得超過10座。但其儲槽容量均在200公秉以下，且所儲存物之閃 火點在攝氏70度以上未達200度者，得設置20座以下；儲存物之閃火點在攝氏200度以 上者，無設置數量之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00207', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品試驗方法及判定基準規定，試驗品為粉粒狀者，進行氧化性固體判定，試驗 方式之標準物質或還原劑，下列何者錯誤？', '["燃燒試驗之標準物質：過氯酸鉀（特級）及氯酸鉀（1級）", "燃燒試驗之還原劑：木粉", "落錘試驗之標準物質：硝酸鉀（特級）及氯酸鉀（1級）", "落錘試驗之還原劑：紅磷（1級）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00208', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法規定，液化石 油氣販賣場所儲放液化石油氣，總儲氣量不得超過 W 公斤，超過部分得設容器保管室儲放 之。但總儲氣量以X公斤為限。又液化石油氣備用量，供營業使用者，不得超過Y公斤；供 家庭使用者，不得超過Z公斤。請問W、X、Ｙ及Z分別為多少？', '["W=120；X=1,000；Y=100；Z=50", "W=128；X=1,000；Y=80；Z=40", "W=120；X=1,200；Y=60；Z=30", "W=128；X=1,200；Y=100；Z=50"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00209', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法規定，黃磷、 赤磷及過氧化氫分屬第幾類公共危險物品？', '["黃磷：第三類；赤磷：第二類；過氧化氫：第一類", "黃磷：第二類；赤磷：第三類；過氧化氫：第六類", "黃磷：第五類；赤磷：第三類；過氧化氫：第一類", "黃磷：第三類；赤磷：第二類；過氧化氫：第六類"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00210', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法規定，有關公 共危險物品製造場所或一般處理場所構造規定之敘述，下列何者錯誤？', '["牆壁、樑、柱、地板及樓梯，應以不燃材料建造；外牆有延燒之虞者，除出入口外，不得 設置其他開口，且應採用防火構造", "建築物之屋頂，應以不燃材料建造，並以輕質金屬板或其他輕質不燃材料覆蓋", "窗戶及出入口應設置30分鐘以上防火時效之防火門窗；牆壁開口有延燒之虞者，應設置1 小時以上防火時效之常時關閉式防火門", "設於室外之製造或處理液體六類物品之設備，應在周圍設置距地面高度在 50 公分以上之 圍阻措施，或設置具有同等以上效能之防止流出措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00211', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防火牆及防火水幕設置基準規定，有關防火水幕設備緊急電源供電容量時間及水源容量之 敘述，下列何者錯誤？', '["儲槽容量未達1萬公秉者緊急電源供電容量時間為240分鐘", "儲槽容量達1萬公秉以上者緊急電源供電容量時間為360分鐘", "儲槽容量未達1萬公秉者，水源容量不得小於防護該儲槽連續放水120分鐘之水量", "儲槽容量達1萬公秉以上者，水源容量不得小於防護該儲槽連續放水240分鐘之水量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00212', 'fire-eq-eng', 'fire-eq-eng-moex-114-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防火牆及防火水幕設置基準規定，防火水幕之防護高度為12公尺時，其每公尺水幕長度放 水量應在每分鐘多少公升以上？', '["80", "120", "140", "180"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:13+00:00", "source_pdf_sha1": "60003cfa7dbf", "answer_pdf_sha1": "4490a7f85367", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
